/**
 * AI Startup Builder - Frontend
 * React App (Single File Architecture)
 */

import React, { useState, useEffect } from 'react';
import ReactDOM from 'react-dom/client';
import { BrowserRouter, Routes, Route, Link, useNavigate, useParams } from 'react-router-dom';
import axios from 'axios';
import { 
  Sparkles, Layout, Database, Server, Code, Download, 
  Trash2, Plus, LogOut, User, ChevronRight, BookOpen, 
  CreditCard, MessageCircle, Users, Zap, Shield, CheckCircle,
  Menu, X, Copy, ExternalLink
} from 'lucide-react';
import './styles.css';

// ==================== CONFIG ====================
const API_URL = 'http://localhost:5000/api';

axios.interceptors.request.use(config => {
  const token = localStorage.getItem('token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

const NO_CODE_PREVIEW = {
  title: 'NoCode Project Builder',
  description: 'No-code платформа для создания проектов с библиотекой шаблонов, визуальным drag-and-drop редактором, моделями данных, публикацией и командной работой',
  summary: 'Готовый сценарий для конструктора проектов: шаблоны, визуальный редактор, data model, публикация и совместная работа в одном продукте.',
  pages: ['Landing', 'Dashboard', 'Template Library', 'Visual Editor', 'Data Models', 'Publish Center', 'Billing', 'Workspace Settings'],
  components: ['HeroSection', 'ProjectWizard', 'TemplateMarketplace', 'EditorCanvas', 'BlockPalette', 'PropertiesPanel', 'LivePreview', 'PublishDrawer'],
  productModules: ['Мастер создания проекта', 'Библиотека шаблонов', 'Визуальный редактор', 'Data model builder', 'Командная работа', 'Публикация и деплой'],
  apiRoutes: ['GET /api/templates', 'POST /api/projects', 'PUT /api/projects/:id/layout', 'PUT /api/projects/:id/schema', 'POST /api/projects/:id/publish', 'POST /api/projects/:id/deploy'],
  databaseSchema: ['users (id, email, password, fullName, role, plan)', 'projects (id, userId, name, slug, status, templateId, stack)', 'pages (id, projectId, name, path, sections, seoTitle)', 'blocks (id, projectId, pageId, type, props, order)', 'deployments (id, projectId, target, url, status, deployedAt)'],
  fileTree: ['client/src/App.js', 'client/src/styles.css', 'client/src/data/templates.js', 'server/index.js', 'server/routes/projects.js', 'server/routes/templates.js', 'server/models/index.js', 'shared/blueprint.json']
};

const PreviewListCard = ({ icon: Icon, title, items, code }) => (
  <div className={code ? 'preview-card preview-card-code' : 'preview-card'}>
    <h3><Icon size={18} /> {title}</h3>
    {code ? (
      <div className="preview-code-list">
        {items.map((item, index) => <div key={`${title}-${index}`} className="preview-code-line">{item}</div>)}
      </div>
    ) : (
      <ul>
        {items.map((item, index) => <li key={`${title}-${index}`}>{item}</li>)}
      </ul>
    )}
  </div>
);

// ==================== COMPONENTS ====================

// Landing Page
const Landing = () => {
  const navigate = useNavigate();
  
  return (
    <div className="landing">
      <nav className="nav">
        <div className="logo"><Sparkles size={28} /> AI Startup Builder</div>
        <div className="nav-links">
          <Link to="/login" className="btn-secondary">Войти</Link>
          <Link to="/register" className="btn-primary">Начать бесплатно</Link>
        </div>
      </nav>
      
      <header className="hero">
        <h1>Преврати идею в работающее приложение за минуты</h1>
        <p>AI Startup Builder генерирует структуру веб и мобильных приложений из текстового описания</p>
        <button onClick={() => navigate('/register')} className="btn-hero">
          Создать проект <ChevronRight size={20} />
        </button>
      </header>

      <section className="features">
        <div className="feature-card">
          <Zap className="icon-bronze" size={40} />
          <h3>Мгновенная генерация</h3>
          <p>Опиши идею — получи готовую структуру приложения сразу</p>
        </div>
        <div className="feature-card">
          <Code className="icon-bronze" size={40} />
          <h3>Чистый код</h3>
          <p>Генерация лучших практик и современных паттернов разработки</p>
        </div>
        <div className="feature-card">
          <Layout className="icon-bronze" size={40} />
          <h3>Полный стек</h3>
          <p>Frontend, Backend и Database схемы в одном месте</p>
        </div>
      </section>

      <section className="how-it-works">
        <h2>Как это работает</h2>
        <div className="steps">
          <div className="step"><span>1</span><p>Опиши свою идею</p></div>
          <div className="step"><span>2</span><p>Выбери технологический стек</p></div>
          <div className="step"><span>3</span><p>Получи готовую структуру</p></div>
          <div className="step"><span>4</span><p>Начни разработку</p></div>
        </div>
      </section>

      <section className="audience">
        <h2>Для кого это</h2>
        <div className="audience-grid">
          <div><Users size={32} /> <h4>Стартаперы</h4><p>Быстрая валидация идей</p></div>
          <div><BookOpen size={32} /> <h4>Студенты</h4><p>Изучение архитектуры приложений</p></div>
          <div><Code size={32} /> <h4>Разработчики</h4><p>Прототипирование MVP</p></div>
        </div>
      </section>

      <footer className="footer">
        <p>© 2026 AI Startup Builder. Дипломный проект.</p>
      </footer>
    </div>
  );
};

// Auth Forms
const Login = () => {
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const { data } = await axios.post(`${API_URL}/auth/login`, form);
      localStorage.setItem('token', data.token);
      localStorage.setItem('user', JSON.stringify(data.user));
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка входа');
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-box">
        <h2>Вход</h2>
        {error && <div className="error">{error}</div>}
        <form onSubmit={handleSubmit}>
          <input type="email" placeholder="Email" required 
            value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
          <input type="password" placeholder="Пароль" required 
            value={form.password} onChange={e => setForm({...form, password: e.target.value})} />
          <button type="submit" className="btn-primary">Войти</button>
        </form>
        <p>Нет аккаунта? <Link to="/register">Зарегистрироваться</Link></p>
      </div>
    </div>
  );
};

const Register = () => {
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const { data } = await axios.post(`${API_URL}/auth/register`, form);
      localStorage.setItem('token', data.token);
      localStorage.setItem('user', JSON.stringify(data.user));
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка регистрации');
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-box">
        <h2>Регистрация</h2>
        {error && <div className="error">{error}</div>}
        <form onSubmit={handleSubmit}>
          <input type="email" placeholder="Email" required 
            value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
          <input type="password" placeholder="Пароль" required 
            value={form.password} onChange={e => setForm({...form, password: e.target.value})} />
          <button type="submit" className="btn-primary">Создать аккаунт</button>
        </form>
        <p>Уже есть аккаунт? <Link to="/login">Войти</Link></p>
      </div>
    </div>
  );
};

// Dashboard
const Dashboard = () => {
  const [projects, setProjects] = useState([]);
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const u = JSON.parse(localStorage.getItem('user'));
    if (!u) return navigate('/login');
    setUser(u);
    loadProjects();
  }, []);

  const loadProjects = async () => {
    try {
      const { data } = await axios.get(`${API_URL}/projects`);
      setProjects(data);
    } catch (err) {
      if (err.response?.status === 401) navigate('/login');
    }
  };

  const deleteProject = async (id) => {
    if (!window.confirm('Удалить проект?')) return;
    await axios.delete(`${API_URL}/projects/${id}`);
    loadProjects();
  };

  const logout = () => {
    localStorage.clear();
    navigate('/');
  };

  return (
    <div className="dashboard">
      <aside className="sidebar">
        <div className="logo"><Sparkles size={24} /> AI Builder</div>
        <nav>
          <Link to="/dashboard" className="nav-item active"><Layout size={20} /> Проекты</Link>
          <Link to="/generator" className="nav-item"><Zap size={20} /> Новый проект</Link>
          <Link to="/learning" className="nav-item"><BookOpen size={20} /> Обучение</Link>
          <Link to="/integrations" className="nav-item"><Server size={20} /> Интеграции</Link>
        </nav>
        <div className="user-section">
          <span><User size={16} /> {user?.email}</span>
          <button onClick={logout} className="btn-icon"><LogOut size={16} /></button>
        </div>
      </aside>

      <main className="main-content">
        <header className="page-header">
          <h1>Мои проекты</h1>
          <Link to="/generator" className="btn-primary"><Plus size={20} /> Новый проект</Link>
        </header>

        {projects.length === 0 ? (
          <div className="empty-state">
            <Layout size={64} className="icon-muted" />
            <h3>Пока нет проектов</h3>
            <p>Создай свой первый проект с помощью ИИ</p>
            <Link to="/generator" className="btn-secondary">Создать проект</Link>
          </div>
        ) : (
          <div className="projects-grid">
            {projects.map(p => (
              <div key={p._id} className="project-card">
                <div className="project-header">
                  <h3>{p.name}</h3>
                  <span className={`status ${p.status}`}>{p.status}</span>
                </div>
                <p className="project-desc">{p.description}</p>
                <div className="project-meta">
                  <span className="stack-badge">{p.stack}</span>
                  <span className="date">{new Date(p.createdAt).toLocaleDateString('ru-RU')}</span>
                </div>
                <div className="project-actions">
                  <Link to={`/project/${p._id}`} className="btn-text">Открыть <ChevronRight size={16} /></Link>
                  <button onClick={() => deleteProject(p._id)} className="btn-icon danger"><Trash2 size={16} /></button>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

// Generator
const Generator = () => {
  const [form, setForm] = useState({ description: '', stack: 'React' });
  const [loading, setLoading] = useState(false);
  const [mode, setMode] = useState('custom');
  const navigate = useNavigate();

  const isPreviewMode = mode === 'nocode-preview';

  const selectMode = (nextMode) => {
    setMode(nextMode);
    if (nextMode === 'nocode-preview') {
      setForm(current => ({ ...current, stack: 'React' }));
    }
  };

  const createProject = async () => {
    setLoading(true);
    try {
      const payload = {
        description: isPreviewMode ? NO_CODE_PREVIEW.description : form.description,
        stack: form.stack
      };

      const { data } = await axios.post(`${API_URL}/projects`, payload);
      navigate(`/project/${data._id}`);
    } catch (err) {
      alert('Ошибка генерации');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await createProject();
  };

  return (
    <div className="dashboard">
      <aside className="sidebar">
        <div className="logo"><Sparkles size={24} /> AI Builder</div>
        <nav>
          <Link to="/dashboard" className="nav-item"><Layout size={20} /> Проекты</Link>
          <Link to="/generator" className="nav-item active"><Zap size={20} /> Новый проект</Link>
          <Link to="/learning" className="nav-item"><BookOpen size={20} /> Обучение</Link>
        </nav>
      </aside>

      <main className="main-content">
        <div className="generator-page">
          <h1>Генератор проекта</h1>
          <p className="subtitle">Опиши свою идею или переключись в готовый сценарий no-code builder с предпросмотром структуры.</p>

          <div className="generator-mode-switch" role="tablist" aria-label="Режим генерации">
            <button
              type="button"
              className={mode === 'custom' ? 'generator-mode-button active' : 'generator-mode-button'}
              onClick={() => selectMode('custom')}
            >
              Своя идея
            </button>
            <button
              type="button"
              className={isPreviewMode ? 'generator-mode-button active' : 'generator-mode-button'}
              onClick={() => selectMode('nocode-preview')}
            >
              Пример no-code builder
            </button>
          </div>

          {isPreviewMode ? (
            <div className="generator-preview-layout">
              <section className="generator-preview-hero">
                <div className="preview-badge"><Sparkles size={16} /> Готовый шаблон продукта</div>
                <h2>{NO_CODE_PREVIEW.title}</h2>
                <p>{NO_CODE_PREVIEW.summary}</p>

                <div className="preview-stat-grid">
                  <div className="preview-stat">
                    <span>Страницы</span>
                    <strong>{NO_CODE_PREVIEW.pages.length}</strong>
                  </div>
                  <div className="preview-stat">
                    <span>Модули</span>
                    <strong>{NO_CODE_PREVIEW.productModules.length}</strong>
                  </div>
                  <div className="preview-stat">
                    <span>Файлы</span>
                    <strong>{NO_CODE_PREVIEW.fileTree.length}</strong>
                  </div>
                </div>

                <div className="preview-stack-form">
                  <div className="form-group">
                    <label>Технологический стек</label>
                    <select value={form.stack} onChange={e => setForm({...form, stack: e.target.value})}>
                      <option value="React">React + Node.js</option>
                      <option value="Vue">Vue + Node.js</option>
                      <option value="Flutter">Flutter (Mobile)</option>
                      <option value="Python">React + Python/Django</option>
                    </select>
                  </div>
                </div>

                <div className="preview-actions">
                  <button type="button" className="btn-primary btn-large" onClick={createProject} disabled={loading}>
                    {loading ? <><span className="spinner" /> Генерация...</> : <><Sparkles size={20} /> Создать из примера</>}
                  </button>
                  <button
                    type="button"
                    className="btn-secondary"
                    onClick={() => {
                      setForm(current => ({ ...current, description: NO_CODE_PREVIEW.description }));
                      selectMode('custom');
                    }}
                  >
                    Перейти в редактирование
                  </button>
                </div>
              </section>

              <section className="generator-preview-grid">
                <PreviewListCard icon={Layout} title="Страницы" items={NO_CODE_PREVIEW.pages} />
                <PreviewListCard icon={Code} title="Компоненты" items={NO_CODE_PREVIEW.components} />
                <PreviewListCard icon={Sparkles} title="Продуктовые модули" items={NO_CODE_PREVIEW.productModules} />
                <PreviewListCard icon={Server} title="API" items={NO_CODE_PREVIEW.apiRoutes} />
                <PreviewListCard icon={Database} title="Схема данных" items={NO_CODE_PREVIEW.databaseSchema} />
                <PreviewListCard icon={Download} title="Структура ZIP" items={NO_CODE_PREVIEW.fileTree} code />
              </section>
            </div>
          ) : (
            <>
              <form onSubmit={handleSubmit} className="generator-form">
                <div className="form-group">
                  <label>Описание приложения</label>
                  <textarea 
                    placeholder="Например: No-code платформа для создания проектов с шаблонами, редактором и публикацией..."
                    required
                    rows={5}
                    value={form.description}
                    onChange={e => setForm({...form, description: e.target.value})}
                  />
                </div>

                <div className="form-group">
                  <label>Технологический стек</label>
                  <select value={form.stack} onChange={e => setForm({...form, stack: e.target.value})}>
                    <option value="React">React + Node.js</option>
                    <option value="Vue">Vue + Node.js</option>
                    <option value="Flutter">Flutter (Mobile)</option>
                    <option value="Python">React + Python/Django</option>
                  </select>
                </div>

                <button type="submit" className="btn-primary btn-large" disabled={loading}>
                  {loading ? <><span className="spinner" /> Генерация...</> : <><Sparkles size={20} /> Сгенерировать проект</>}
                </button>
              </form>

              <div className="tips">
                <h4><Zap size={16} /> Советы по описанию:</h4>
                <ul>
                  <li>Укажи тип приложения (магазин, блог, соцсеть)</li>
                  <li>Опиши ключевые функции</li>
                  <li>Упомяни целевую аудиторию</li>
                  <li>Для no-code builder укажи шаблоны, визуальный редактор, data model и публикацию</li>
                </ul>
                <button type="button" className="btn-secondary" onClick={() => selectMode('nocode-preview')}>
                  Открыть готовый предпросмотр no-code builder
                </button>
              </div>
            </>
          )}
        </div>
      </main>
    </div>
  );
};


// Project Details
const ProjectDetail = () => {
  const { id } = useParams();
  const [project, setProject] = useState(null);
  const [activeTab, setActiveTab] = useState('frontend');
  const [generating, setGenerating] = useState(false);
  const [downloading, setDownloading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    loadProject();
  }, [id]);

  const loadProject = async () => {
    try {
      const { data } = await axios.get(`${API_URL}/projects/${id}`);
      setProject(data);
    } catch (err) {
      navigate('/dashboard');
    }
  };

  const generateCode = async () => {
    setGenerating(true);
    try {
      const { data } = await axios.post(`${API_URL}/projects/${id}/generate-code`);
      setProject({ ...project, generatedCode: data });
    } catch (err) {
      alert('Ошибка генерации кода');
    } finally {
      setGenerating(false);
    }
  };

  const downloadProject = async () => {
    setDownloading(true);
    try {
      const response = await axios.get(`${API_URL}/projects/${id}/export`, {
        responseType: 'blob'
      });

      const contentDisposition = response.headers['content-disposition'] || '';
      const match = contentDisposition.match(/filename="?([^\"]+)"?/i);
      const fileName = match?.[1] || `${project.name.replace(/\s+/g, '_')}.zip`;

      const url = window.URL.createObjectURL(new Blob([response.data], { type: 'application/zip' }));
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      alert('Не удалось скачать архив проекта');
    } finally {
      setDownloading(false);
    }
  };

  if (!project) return <div className="loading">Загрузка...</div>;

  return (
    <div className="dashboard">
      <aside className="sidebar">
        <div className="logo"><Sparkles size={24} /> AI Builder</div>
        <nav>
          <Link to="/dashboard" className="nav-item"><Layout size={20} /> Проекты</Link>
          <Link to="/generator" className="nav-item"><Zap size={20} /> Новый проект</Link>
        </nav>
      </aside>

      <main className="main-content">
        <div className="project-detail">
          <header className="detail-header">
            <div>
              <h1>{project.name}</h1>
              <p>{project.description}</p>
              <span className="stack-badge large">{project.stack}</span>
            </div>
            <div className="header-actions">
              <button 
                onClick={generateCode} 
                className="btn-secondary"
                disabled={generating || downloading}
              >
                {generating ? <><span className="spinner" /> Генерация...</> : <><Code size={18} /> Сгенерировать код</>}
              </button>
              <button onClick={downloadProject} className="btn-primary" disabled={generating || downloading}>
                {downloading ? <><span className="spinner" /> Сборка ZIP...</> : <><Download size={18} /> Скачать ZIP</>}
              </button>
            </div>
          </header>

          <div className="tabs">
            <button className={activeTab === 'frontend' ? 'active' : ''} onClick={() => setActiveTab('frontend')}>
              <Layout size={18} /> Frontend
            </button>
            <button className={activeTab === 'backend' ? 'active' : ''} onClick={() => setActiveTab('backend')}>
              <Server size={18} /> Backend
            </button>
            <button className={activeTab === 'database' ? 'active' : ''} onClick={() => setActiveTab('database')}>
              <Database size={18} /> Database
            </button>
          </div>

          <div className="tab-content">
            {activeTab === 'frontend' && (
              <div className="structure-grid">
                <div className="structure-card">
                  <h3><Layout size={20} /> Страницы</h3>
                  <ul>{project.structure.pages.map((p, i) => <li key={i}><CheckCircle size={14} /> {p}</li>)}</ul>
                </div>
                <div className="structure-card">
                  <h3><Code size={20} /> Компоненты</h3>
                  <ul>{project.structure.components.map((c, i) => <li key={i}><CheckCircle size={14} /> {c}</li>)}</ul>
                </div>
                {project.structure.productModules?.length > 0 && (
                  <div className="structure-card">
                    <h3><Sparkles size={20} /> Продуктовые модули</h3>
                    <ul>{project.structure.productModules.map((moduleName, i) => <li key={i}><CheckCircle size={14} /> {moduleName}</li>)}</ul>
                  </div>
                )}
                {project.structure.fileTree?.length > 0 && (
                  <div className="structure-card full">
                    <h3><Download size={20} /> Файлы, которые войдут в ZIP</h3>
                    <div className="code-block">
                      {project.structure.fileTree.map((file, i) => (
                        <div key={i} className="code-line">{file}</div>
                      ))}
                    </div>
                  </div>
                )}
                {project.generatedCode?.frontend && (
                  <div className="structure-card full">
                    <h3><Code size={20} /> Сгенерированный код Frontend</h3>
                    <pre className="code-block"><code>{project.generatedCode.frontend}</code></pre>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'backend' && (
              <div className="structure-card full">
                <h3><Server size={20} /> API Маршруты</h3>
                <div className="code-block">
                  {project.structure.apiRoutes.map((r, i) => (
                    <div key={i} className="code-line"><span className="method">{r.split(' ')[0]}</span> {r.split(' ')[1]}</div>
                  ))}
                </div>
                {project.generatedCode?.backend && (
                  <>
                    <h3 style={{marginTop: '2rem'}}><Code size={20} /> Сгенерированный код Backend</h3>
                    <pre className="code-block"><code>{project.generatedCode.backend}</code></pre>
                  </>
                )}
              </div>
            )}

            {activeTab === 'database' && (
              <div className="structure-card full">
                <h3><Database size={20} /> Схема базы данных</h3>
                <div className="code-block">
                  {project.structure.databaseSchema.map((s, i) => (
                    <div key={i} className="schema-item">
                      <span className="table-name">{s.split(' ')[0]}</span>
                      <span className="fields">{s.substring(s.indexOf('('))}</span>
